// SAFETY: seed numbers are FAKE strangers' numbers. Only dial the allowlist.
// (+972585121998 is intentionally NOT here — it is the human-transfer target.)
const ALLOWED = ['+972585121998'];
const HOURS = ['שתים עשרה','אחת','שתיים','שלוש','ארבע','חמש','שש','שבע','שמונה','תשע','עשר','אחת עשרה'];
const PARTY = {1:'סועד אחד',2:'שני סועדים',3:'שלושה סועדים',4:'ארבעה סועדים',5:'חמישה סועדים',6:'שישה סועדים',7:'שבעה סועדים',8:'שמונה סועדים',9:'תשעה סועדים',10:'עשרה סועדים'};

function spokenTime(dt) {
  const h12 = HOURS[dt.hour % 12];
  let base;
  if (dt.minute === 0) base = h12;
  else if (dt.minute === 30) base = h12 + ' וחצי';
  else if (dt.minute === 15) base = h12 + ' ורבע';
  else if (dt.minute === 45) base = 'רבע ל' + HOURS[(dt.hour + 1) % 12];
  else base = h12 + ' ' + String(dt.minute).padStart(2, '0');
  if (dt.minute === 0) {
    if (dt.hour >= 12 && dt.hour < 17) return base + ' בצהריים';
    if (dt.hour >= 17) return base + ' בערב';
    return base + ' בבוקר';
  }
  return base;
}

const now = $now.setZone('Asia/Jerusalem');
const out = [];
let skipped = 0;
for (const item of $input.all()) {
  const r = item.json;
  if (!ALLOWED.includes(r.phone)) { skipped++; continue; }
  const local = DateTime.fromISO(r.reserved_for).setZone('Asia/Jerusalem');
  out.push({ json: {
    to_number: r.phone,
    customer_name: r.customer_name,
    reservation_id: r.reservation_id,
    dynamic_variables: {
      customer_name: r.customer_name,
      reservation_time: local.toFormat('HH:mm'),
      reservation_time_spoken: spokenTime(local),
      party_size: String(r.party_size),
      party_size_spoken: PARTY[r.party_size] || (r.party_size + ' סועדים'),
      reservation_id: r.reservation_id,
      today: now.toFormat('yyyy-MM-dd'),
      now_local: now.toFormat("yyyy-MM-dd'T'HH:mm:ssZZ")
    }
  }});
}
console.log('callable:', out.length, '| skipped (not in allowlist):', skipped);
return out;

// Pair each placed call's conversation_id with the reservation it was about.
// (Item order from Place Call matches the batch input order.)
const resp = $input.all();
const batch = $('Batch Of 5').all();
const pairs = resp.map((r, i) => ({
  conversation_id: r.json.conversation_id,
  reservation_id: batch[i] && batch[i].json.reservation_id
})).filter(p => p.conversation_id);
return [{ json: { ids: pairs.map(p => p.conversation_id), pairs } }];

const ids = $('Collect Conversation IDs').first().json.ids;
const convs = $input.first().json.conversations || [];
const statusById = {};
for (const c of convs) statusById[c.conversation_id] = c.status;
const finished = ids.filter(id => ['done', 'failed'].includes(statusById[id] || ''));
// Safety valve: a no-answer call stays 'initiated' forever — give up after ~5 min of polling
const attempt = $runIndex;
const all_done = finished.length === ids.length || attempt >= 25;
return [{ json: { all_done, attempt, finished: finished.length, total: ids.length } }];

// THE GUARANTEE: a completed call about a pending reservation must leave a status change
// or a scheduled callback. If neither happened, classify deterministically:
//   - call never connected / instant hangup (<5s)  -> leave pending: next batch run redials
//   - guest actually engaged but decided nothing   -> flag needs_human for follow-up
// NOTE: pairs/conv-info come from the LAST loop iteration — fine for single-batch runs
// (the demo and any run with <=5 calls); multi-batch accumulation is a known TODO.
const pairs = $('Collect Conversation IDs').first().json.pairs || [];
const convs = $('Check Call Statuses').first().json.conversations || [];
const reservations = $('Fetch Outcomes').all().map(i => i.json);
const callbacks = $('Fetch Scheduled Callbacks').all().map(i => i.json).filter(j => j && j.reservation_id);

const convInfo = {};
for (const c of convs) convInfo[c.conversation_id] = { status: c.status, dur: c.call_duration_secs || 0 };
const statusById = {};
for (const r of reservations) statusById[r.id] = r.status;
const hasCallback = new Set(callbacks.map(c => c.reservation_id));

const retryNextRun = [];
const needsHuman = [];
for (const p of pairs) {
  if (statusById[p.reservation_id] !== 'pending' || hasCallback.has(p.reservation_id)) continue;
  const info = convInfo[p.conversation_id];
  const engaged = info && info.status === 'done' && info.dur >= 5;
  (engaged ? needsHuman : retryNextRun).push(p.reservation_id);
}
// Sentinel UUID keeps the PATCH below a valid no-op when there is nothing to repair
const idFilter = needsHuman.length ? needsHuman.join(',') : '00000000-0000-0000-0000-000000000000';
return [{ json: { needsHuman, retryNextRun, idFilter } }];

const items = $('Fetch Outcomes').all().map(i => i.json);
const rec = $('Reconcile (Deterministic Guard)').first().json;
const by = {};
for (const r of items) by[r.status] = (by[r.status] || 0) + 1;
return [{ json: {
  ran_at: $now.setZone('Asia/Jerusalem').toISO(),
  reservations_today: items.length,
  by_status: by,
  flagged_needs_human: rec.needsHuman,
  unanswered_will_retry_on_next_run: rec.retryNextRun,
  details: items.map(r => ({ name: r.customers && r.customers.name, phone: r.customers && r.customers.phone, time: r.reserved_for, party: r.party_size, status: r.status }))
}}];
